    22→/**
    23→ * Generate embedding for text using the AI provider fallback system.
    24→ * Chain: OpenAI text-embedding-3-small → NIM NV-EmbedQA → NIM Nemotron-Embed-VL
    25→ */
    26→async function generateEmbedding(text) {
    27→  if (!text || text.trim().length === 0) {
    28→    throw new Error('Cannot generate embedding for empty text');
    29→  }
    30→
    31→  return aiProvider.generateEmbedding(text.substring(0, 8000));
    32→}
    33→
    34→/**
    35→ * Build text representation of candidate profile for embedding
    36→ */
    37→function buildCandidateProfileText(profile) {
    38→  const parts = [];
    39→
    40→  // Headline and bio
    41→  if (profile.headline) parts.push(`Headline: ${profile.headline}`);
    42→  if (profile.bio) parts.push(`Bio: ${profile.bio}`);
    43→
    44→  // Skills
    45→  if (profile.skills && profile.skills.length > 0) {
    46→    const skillsText = profile.skills
    47→      .map(s => `${s.skill_name} (level ${s.level})`)
    48→      .join(', ');
    49→    parts.push(`Skills: ${skillsText}`);
    50→  }
    51→
    52→  // Experience
    53→  if (profile.experience && profile.experience.length > 0) {
    54→    profile.experience.forEach(exp => {
